  creditCard() {
    // Generate realistic card number using Luhn algorithm
    // Common card prefixes:
    // Visa: 4xxx, MasterCard: 51-55, Amex: 34/37, Discover: 6011
    const cardTypes = [
      { prefix: "4", length: 16, name: "Visa" },
      { prefix: "51", length: 16, name: "MasterCard" },
      { prefix: "52", length: 16, name: "MasterCard" },
      { prefix: "53", length: 16, name: "MasterCard" },
      { prefix: "54", length: 16, name: "MasterCard" },
      { prefix: "55", length: 16, name: "MasterCard" },
      { prefix: "37", length: 15, name: "Amex" },
      { prefix: "34", length: 15, name: "Amex" },
      { prefix: "6011", length: 16, name: "Discover" },
    ];

    const cardType = this.randomItem(cardTypes);
    let number = cardType.prefix;

    // Generate random digits (leaving space for checksum)
    while (number.length < cardType.length - 1) {
      number += this.random(0, 9);
    }

    // Calculate Luhn checksum
    let sum = 0;
    let shouldDouble = true;
    // Traverse from right to left (excluding the check digit position)
    for (let i = number.length - 1; i >= 0; i--) {
      let digit = parseInt(number[i]);

      if (shouldDouble) {
        digit *= 2;
        if (digit > 9) digit -= 9;
      }

      sum += digit;
      shouldDouble = !shouldDouble;
    }

    // Calculate check digit
    const checkDigit = (10 - (sum % 10)) % 10;
    number += checkDigit;

    // Format: XXXX XXXX XXXX XXXX (or XXXX XXXXXX XXXXX for Amex)
    if (cardType.length === 15) {
      return number
        .match(/.{1,4}|.{1,6}|.{1,5}/g)
        .slice(0, 3)
        .join(" ");
    } else {
      return number.match(/.{1,4}/g).join(" ");
    }
  }

  cvv() {
    return String(this.random(100, 999));
  }

  expiryDate() {
    const month = String(this.random(1, 12)).padStart(2, "0");
    const year = String(this.random(24, 30));
    return `${month}/${year}`;
  }

  date() {
    const year = this.random(1950, 2005);
    const month = String(this.random(1, 12)).padStart(2, "0");
    const day = String(this.random(1, 28)).padStart(2, "0");
    return `${year}-${month}-${day}`;
  }

  password() {
    const chars =
      "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789!@#$%^&*";
    let password = "";
    for (let i = 0; i < 12; i++) {
      password += chars.charAt(Math.floor(Math.random() * chars.length));
    }
    return password;
  }

